import subprocess
from typing import List, Dict

class DependencyManager:
    def __init__(self):
        self.requirements = []

    def generate_lock_file(self, requirements: List[str]) -> None:
        """
        Generate a Poetry lock file from the given list of dependencies.

        Args:
            requirements (List[str]): The list of dependencies with version constraints.
                e.g., ["numpy==1.22.3", "pandas==1.4.2"]
        """
        # Create a new poetry project
        subprocess.run(["poetry", "init"])

        # Install the required dependencies
        for requirement in requirements:
            subprocess.run(["poetry", "add", requirement])

        # Generate the lock file
        subprocess.run(["poetry", "lock"])

    def update_lock_file(self, new_requirements: List[str]) -> None:
        """
        Update an existing Poetry lock file with new dependency versions.

        Args:
            new_requirements (List[str]): The updated list of dependencies with version constraints.
                e.g., ["numpy==1.23.0", "pandas==1.4.3"]
        """
        # Remove the old lock file
        subprocess.run(["rm", ".poetry/lock"])

        # Update the lock file using poetry update
        subprocess.run(["poetry", "update"])

    def manage_requirements_txt(self, requirements: List[str]) -> None:
        """
        Manage a requirements.txt file with hashes.

        Args:
            requirements (List[str]): The list of dependencies with version constraints and hashes.
                e.g., ["numpy==1.22.3#sha256=...","pandas==1.4.2#sha256=..."]
        """
        # Install the required dependencies
        for requirement in requirements:
            subprocess.run(["pip", "install", "-r", "-n", requirement])

    def generate_requirements_txt(self, installed_packages: Dict[str, str]) -> None:
        """
        Generate a requirements.txt file with hashes from installed packages.

        Args:
            installed_packages (Dict[str, str]): A dictionary of installed packages with version and hash.
                e.g., {"numpy": "1.22.3#sha256=...", "pandas": "1.4.2#sha256=..."}
        """
        # Create a requirements.txt file
        with open("requirements.txt", "w") as f:
            for package, version in installed_packages.items():
                f.write(f"{package}=={version}\n")

def main() -> None:
    manager = DependencyManager()

    # Example usage: Generate a Poetry lock file from dependencies
    requirements = ["numpy==1.22.3", "pandas==1.4.2"]
    manager.generate_lock_file(requirements)

    # Example usage: Update an existing Poetry lock file with new dependency versions
    new_requirements = ["numpy==1.23.0", "pandas==1.4.3"]
    manager.update_lock_file(new_requirements)

    # Example usage: Manage a requirements.txt file with hashes
    requirements = ["numpy==1.22.3#sha256=...", "pandas==1.4.2#sha256=..."]
    manager.manage_requirements_txt(requirements)

    # Example usage: Generate a requirements.txt file with hashes from installed packages
    installed_packages = {"numpy": "1.22.3#sha256=...", "pandas": "1.4.2#sha256=..."}
    manager.generate_requirements_txt(installed_packages)

if __name__ == "__main__":
    main()